mapper.select:
SELECT log_id, scene_type, scene_name, request_summary, response_summary, status, cost_millis,
       token_count, risk_level, sensitive_hit, error_message, user_id, username, dept_id, tenant_id,
       create_time
FROM ai_governance_log


        AND scene_type = #{sceneType}


        AND scene_name LIKE CONCAT('%', #{sceneName}, '%')


        AND status = #{status}


        AND risk_level = #{riskLevel}


        AND sensitive_hit = #{sensitiveHit}


ORDER BY create_time DESC, log_id DESC
